var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아하하~ 샤레이드에 이렇게 분위기 좋은 바가 있는 줄은 몰랐어요오.","JPN":"あはは～シャレードにこんないい感じのバーがあったなんて知りませんでしたあ～。","ENG":"Ah hah hah! I didn't know Charade had a bar with such a nice atmosphere.","TWN":"啊哈哈！沒想到在查雷德還有氛圍這麼好的酒吧喔～！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"대체 이런 곳을 어떻게 알고 계신 거예요오?","JPN":"どこでこんな場所を知ったんですか～？","ENG":"How did you even find out about a place like this?","TWN":"你到底是怎麼知道這個地方的？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 님은 정말 대단하시다니까아~","JPN":"さすがスワンさん、すごいです～！","ENG":"You're amazing, Miss Swan.","TWN":"史旺真是太厲害了～"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여기 마스터가 입이 무겁거든요. 조용하게 마시고 싶을 때 가끔 찾는 답니다.","JPN":"ここのマスターは口が堅い方でして。たまに静かに飲みたい時はここに来るんです。","ENG":"The owner here knows how to hold his tongue. I frequent this place whenever I want to drink quietly.","TWN":"這裡的老闆嘴很嚴。有時候想安靜地喝一杯，就會來這裡。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"소란스럽게만 굴지 않는다면, 오늘은 몇 잔이든 마셔도 괜찮아요.","JPN":"騒がしくさえしなければ、今日は何杯でも飲んでいいですよ。","ENG":"As long as you're not loud, you can have more drinks tonight.","TWN":"你只要不吵鬧，今天喝幾杯都沒問題。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"진짜요오? 이거 한 잔에 제 월급보다도 비싼데요오?","JPN":"本当ですかあ～？　この一杯、私の給料よりも高いんですけどお～？","ENG":"Really? But a drink here costs more than my monthly paycheck.","TWN":"真的嗎？這一杯比我的月工資還貴呢，嗝——？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 제 사람 챙길 정도의 배포는 되니까.","JPN":"心配は要りません。そのぐらい奢れますから。","ENG":"Don't worry. I know how to treat my people.","TWN":"不用擔心。我有足夠的能力照顧我的人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"하아~","JPN":"はあ～","ENG":"*Sigh*","TWN":"唉~"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"이렇게 분위기 좋은 바에, 이렇게 맛있는 술에, 최고의 여배우까지 옆에 계신데에…….","JPN":"こんなにいい雰囲気のバーで、こんなにおいしいお酒が飲めて、最高の女優と一緒なのに……","ENG":"I'm at a bar with good vibes, good booze, and a famous actress sitting next to me...","TWN":"在這麼好氛圍的酒吧裡，喝著這麼美味的酒，還有最棒的女演員在旁邊……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"어째서 좋은 남자는 어디에도 보이지 않는 걸까요오?","JPN":"どうしていい男はどこにもいないんでしょう？","ENG":"But where are all the handsome men?","TWN":"為什麼好男人總是無處可尋呢？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"올해 내로 새로운 남자를 찾아서 결혼은 할 수 있을까요오?","JPN":"私、今年中に新しい男を見つけて結婚できるでしょうかあ？","ENG":"Do you think I'll be able to find someone new to get married to this year?","TWN":"今年能找到新男友結婚嗎嗝……？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우리 매니저가 결혼 상대를 찾고 계셨군요.","JPN":"マネージャーは結婚相手を探していたのですね。","ENG":"I didn't know my manager was looking for someone to marry.","TWN":"原來我們的經紀人在找結婚對象啊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 주소로 가시면, 수트 핏이 잘 어울리고 돈도 잘 버는 사장님을 만날 수 있을 거예요.","JPN":"この住所に行けば、スーツが良く似合うお金持ちの社長さんにお会いできますよ。","ENG":"If you go to this address, you'll be able to meet a CEO who looks great in a suit and makes a lot of money.","TWN":"去這個地方，你會遇到一個穿西裝很帥，而且很會賺錢的老闆。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"저, 정말인가요!?","JPN":"ほ、本当ですかあ！？","ENG":"R-really?!","TWN":"真，真的嗎！?"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론이에요.","JPN":"ええ、もちろんです。","ENG":"Yes.","TWN":"當然。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만나 보시고 나중에 경과를 알려주세요.","JPN":"お会いしてみて、あとで話を聞かせてくださいね。","ENG":"Let me know how it went later.","TWN":"見過之後請告訴我結果。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"하핫! 싸랑해요오! 스완니임~!","JPN":"あははっ！　大好きですう、スワンさぁん～！","ENG":"Haha! I love you, Swan!","TWN":"哈哈！我愛你！史旺！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 님은 정말로오 제 생명에에…… ","JPN":"スワンさんは、本当に私の命のおん……… ","ENG":"You're really my savior...","TWN":"史旺你就是我生命中的……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"쿨, 쿠우울~","JPN":"すう……すう……","ENG":"Zzz...","TWN":"呃，呼嚕嚕……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"때마침 잘 오셨군요. 이쪽이랍니다.","JPN":"ちょうどいいところに来ましたね。こちらです。","ENG":"Right on time. This way.","TWN":"你來得正好。這邊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"하하, 이것 참…….","JPN":"はは、まいったな……","ENG":"Haha. Oh, my...","TWN":"哈哈，這還真是……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"무척이나 유명하신 분께서 정보를 사고 싶다고 하셔서, 장난인가 싶었는데.","JPN":"かなりの有名人が情報を買いたいというので、何のいたずらかと思いましたが。","ENG":"I thought it was a joke when a famous person said she wanted to buy information from me.","TWN":"聽說一位非常有名的人想買我情報，我還以為是在開玩笑呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"뜻밖의 장소에서, 뜻밖의 귀인을 만나게 되네요.","JPN":"思いもよらない場所で、思いもよらない貴人に出会えましたね。","ENG":"I didn't expect to meet such a person in a place like this.","TWN":"在意想不到的地方，遇到了意想不到的貴人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};